/// Primary activation behavior for auto-explore controls.
///
/// Keeping this as data prevents the compact button and settings sheet from
/// drifting when auto-explore is armed but temporarily yielded to the user.
enum AutoExplorePrimaryAction {
  startOrResume,
  pause,
  resumeFromTemporaryYield,
}

/// Replayable presentation state for auto-explore controls.
///
/// The service can be exploring while user interaction temporarily owns motion.
/// Controls should not present that state as active auto-motion; otherwise the
/// pause icon/tooltip contradict the user-correction pause badge.
class AutoExploreControlStatus {
  final bool isExploring;
  final bool isPaused;
  final bool pausedByUserCorrection;

  const AutoExploreControlStatus({
    required this.isExploring,
    required this.isPaused,
    required this.pausedByUserCorrection,
  });

  /// True only while auto-explore is actively driving motion.
  bool get isMotionActive =>
      isExploring && !isPaused && !pausedByUserCorrection;

  /// True while auto-explore is armed but temporarily yielded to the user.
  bool get isTemporarilyYielded =>
      isExploring && !isPaused && pausedByUserCorrection;

  /// True when the primary control should present pausing active auto-motion.
  bool get showsPauseAction => isMotionActive;

  /// Replayable primary action for button/sheet activation.
  AutoExplorePrimaryAction get primaryAction {
    if (isMotionActive) return AutoExplorePrimaryAction.pause;
    if (isTemporarilyYielded) {
      return AutoExplorePrimaryAction.resumeFromTemporaryYield;
    }
    return AutoExplorePrimaryAction.startOrResume;
  }

  /// True when tapping the primary control should resume from a temporary yield
  /// instead of toggling into a fully paused state.
  bool get resumesFromTemporaryYield =>
      primaryAction == AutoExplorePrimaryAction.resumeFromTemporaryYield;

  String tooltip({
    required String startLabel,
    required String pauseLabel,
    required String yieldedLabel,
  }) {
    if (isMotionActive) return pauseLabel;
    if (isTemporarilyYielded) return yieldedLabel;
    return startLabel;
  }
}

import 'package:flutter_fractals/core/models/export_options.dart';

const int defaultCustomExportWidth = 1920;
const int defaultCustomExportHeight = 1080;

int resolveCustomExportDimension({
  required String fieldText,
  required int? currentValue,
  required int fallback,
}) {
  final parsed = int.tryParse(fieldText.trim());
  if (parsed != null && parsed > 0) return parsed;
  if (currentValue != null && currentValue > 0) return currentValue;
  return fallback;
}

ExportOptions withResolvedCustomExportDimensions({
  required ExportOptions options,
  required String widthText,
  required String heightText,
}) {
  return options.copyWith(
    customWidth: resolveCustomExportDimension(
      fieldText: widthText,
      currentValue: options.customWidth,
      fallback: defaultCustomExportWidth,
    ),
    customHeight: resolveCustomExportDimension(
      fieldText: heightText,
      currentValue: options.customHeight,
      fallback: defaultCustomExportHeight,
    ),
  );
}

import 'package:equatable/equatable.dart';

/// Supported export image formats
enum ExportFormat {
  png,
  jpg,
  webp,
}

extension ExportFormatExtension on ExportFormat {
  String get extension {
    switch (this) {
      case ExportFormat.png:
        return 'png';
      case ExportFormat.jpg:
        return 'jpg';
      case ExportFormat.webp:
        return 'webp';
    }
  }

  String get mimeType {
    switch (this) {
      case ExportFormat.png:
        return 'image/png';
      case ExportFormat.jpg:
        return 'image/jpeg';
      case ExportFormat.webp:
        return 'image/webp';
    }
  }

  String get displayName {
    switch (this) {
      case ExportFormat.png:
        return 'PNG';
      case ExportFormat.jpg:
        return 'JPG';
      case ExportFormat.webp:
        return 'WebP';
    }
  }
}

/// Preset resolution options for export
enum ExportResolution {
  screen, // Current screen resolution
  hd, // 1280x720
  fullHd, // 1920x1080
  quadHd, // 2560x1440
  uhd4k, // 3840x2160
  instagram, // 1080x1080 (square)
  instagramStory, // 1080x1920 (9:16)
  twitter, // 1200x675 (16:9)
  custom,
}

extension ExportResolutionExtension on ExportResolution {
  String get displayName {
    switch (this) {
      case ExportResolution.screen:
        return 'Screen';
      case ExportResolution.hd:
        return 'HD (1280×720)';
      case ExportResolution.fullHd:
        return 'Full HD (1920×1080)';
      case ExportResolution.quadHd:
        return '2K (2560×1440)';
      case ExportResolution.uhd4k:
        return '4K (3840×2160)';
      case ExportResolution.instagram:
        return 'Instagram (1080×1080)';
      case ExportResolution.instagramStory:
        return 'Instagram Story (1080×1920)';
      case ExportResolution.twitter:
        return 'Twitter (1200×675)';
      case ExportResolution.custom:
        return 'Custom';
    }
  }

  /// Returns (width, height) for preset resolutions
  /// Returns null for screen (use device size) or custom (user specified)
  (int, int)? get dimensions {
    switch (this) {
      case ExportResolution.screen:
        return null;
      case ExportResolution.hd:
        return (1280, 720);
      case ExportResolution.fullHd:
        return (1920, 1080);
      case ExportResolution.quadHd:
        return (2560, 1440);
      case ExportResolution.uhd4k:
        return (3840, 2160);
      case ExportResolution.instagram:
        return (1080, 1080);
      case ExportResolution.instagramStory:
        return (1080, 1920);
      case ExportResolution.twitter:
        return (1200, 675);
      case ExportResolution.custom:
        return null;
    }
  }

  bool get isSocialPreset {
    return this == ExportResolution.instagram ||
        this == ExportResolution.instagramStory ||
        this == ExportResolution.twitter;
  }
}

/// Metadata to embed in exported images
class ExportMetadata extends Equatable {
  final String? title;
  final String? description;
  final String fractalType;
  final Map<String, Object> parameters;
  final DateTime createdAt;
  final String appVersion;

  const ExportMetadata({
    this.title,
    this.description,
    required this.fractalType,
    required this.parameters,
    required this.createdAt,
    this.appVersion = '1.0.0',
  });

  Map<String, String> toExifMap() {
    return {
      'Software': 'Flutter Fractals $appVersion',
      'ImageDescription':
          description ?? 'Fractal artwork created with Flutter Fractals',
      'Artist': 'Flutter Fractals',
      'Copyright': '© ${createdAt.year} Flutter Fractals',
      'UserComment': _buildUserComment(),
    };
  }

  String _buildUserComment() {
    final buffer = StringBuffer();
    buffer.writeln('Fractal Type: $fractalType');
    buffer.writeln('Created: ${createdAt.toIso8601String()}');
    buffer.writeln('Parameters:');
    for (final entry in parameters.entries) {
      buffer.writeln('  ${entry.key}: ${entry.value}');
    }
    return buffer.toString();
  }

  @override
  List<Object?> get props =>
      [title, description, fractalType, parameters, createdAt, appVersion];
}

/// Complete export configuration
class ExportOptions extends Equatable {
  static const Object _unset = Object();

  final ExportFormat format;
  final ExportResolution resolution;
  final int? customWidth;
  final int? customHeight;
  final bool transparentBackground;
  final int quality; // 1-100, for JPG/WebP
  final bool embedMetadata;
  final ExportMetadata? metadata;
  final bool addWatermark;
  final String? watermarkText;

  const ExportOptions({
    this.format = ExportFormat.png,
    this.resolution = ExportResolution.fullHd,
    this.customWidth,
    this.customHeight,
    this.transparentBackground = false,
    this.quality = 95,
    this.embedMetadata = true,
    this.metadata,
    this.addWatermark = false,
    this.watermarkText,
  });

  static T? _nullableCopyWithValue<T>({
    required Object? candidate,
    required T? currentValue,
    required String fieldName,
  }) {
    assert(
      identical(candidate, _unset) || candidate == null || candidate is T,
      '$fieldName must be a $T? value',
    );

    return identical(candidate, _unset) ? currentValue : candidate as T?;
  }

  int _positiveRoundedScreenDimension(double value) {
    if (!value.isFinite || value <= 0) return 1;
    return value.round().clamp(1, 1 << 30);
  }

  int _customOrScreenDimension(int? customValue, double screenValue) {
    if (customValue != null && customValue > 0) return customValue;
    return _positiveRoundedScreenDimension(screenValue);
  }

  double _safeDimensionRatio(int targetDimension, double screenDimension) {
    final safeScreenDimension =
        _positiveRoundedScreenDimension(screenDimension);
    return targetDimension / safeScreenDimension;
  }

  bool _preservesPresetOrientation() {
    return resolution.isSocialPreset;
  }

  (int, int)? _orientedPresetDimensions(
      double screenWidth, double screenHeight) {
    final dims = resolution.dimensions;
    if (dims == null) return null;

    final width = dims.$1;
    final height = dims.$2;
    final isPresetSquare = width == height;
    if (isPresetSquare || _preservesPresetOrientation()) return dims;

    final screenPortrait = screenHeight > screenWidth;
    final presetPortrait = height > width;

    if (screenPortrait != presetPortrait) {
      return (height, width);
    }

    return dims;
  }

  /// Calculate the pixel ratio needed to achieve target resolution
  double calculatePixelRatio(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      // Use the larger ratio to ensure we meet target resolution
      final widthRatio = _safeDimensionRatio(dims.$1, screenWidth);
      final heightRatio = _safeDimensionRatio(dims.$2, screenHeight);
      // Use max to ensure we hit the target resolution on both axes
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    if (resolution == ExportResolution.custom) {
      final targetWidth = _customOrScreenDimension(customWidth, screenWidth);
      final targetHeight = _customOrScreenDimension(customHeight, screenHeight);
      final widthRatio = _safeDimensionRatio(targetWidth, screenWidth);
      final heightRatio = _safeDimensionRatio(targetHeight, screenHeight);
      return (widthRatio > heightRatio ? widthRatio : heightRatio)
          .clamp(1.0, 8.0);
    }

    return 2.5; // Default for screen resolution
  }

  /// Get the target dimensions for this export
  (int, int) getTargetDimensions(double screenWidth, double screenHeight) {
    final dims = _orientedPresetDimensions(screenWidth, screenHeight);
    if (dims != null) {
      return dims;
    }

    if (resolution == ExportResolution.custom) {
      return (
        _customOrScreenDimension(customWidth, screenWidth),
        _customOrScreenDimension(customHeight, screenHeight),
      );
    }

    // Screen resolution
    return (
      _positiveRoundedScreenDimension(screenWidth),
      _positiveRoundedScreenDimension(screenHeight),
    );
  }

  ExportOptions copyWith({
    ExportFormat? format,
    ExportResolution? resolution,
    Object? customWidth = _unset,
    Object? customHeight = _unset,
    bool? transparentBackground,
    int? quality,
    bool? embedMetadata,
    Object? metadata = _unset,
    bool? addWatermark,
    Object? watermarkText = _unset,
  }) {
    assert(
      identical(metadata, _unset) ||
          metadata == null ||
          metadata is ExportMetadata,
      'metadata must be an ExportMetadata? value',
    );
    assert(
      identical(watermarkText, _unset) ||
          watermarkText == null ||
          watermarkText is String,
      'watermarkText must be a String? value',
    );

    return ExportOptions(
      format: format ?? this.format,
      resolution: resolution ?? this.resolution,
      customWidth: _nullableCopyWithValue<int>(
        candidate: customWidth,
        currentValue: this.customWidth,
        fieldName: 'customWidth',
      ),
      customHeight: _nullableCopyWithValue<int>(
        candidate: customHeight,
        currentValue: this.customHeight,
        fieldName: 'customHeight',
      ),
      transparentBackground:
          transparentBackground ?? this.transparentBackground,
      quality: quality ?? this.quality,
      embedMetadata: embedMetadata ?? this.embedMetadata,
      metadata: _nullableCopyWithValue<ExportMetadata>(
        candidate: metadata,
        currentValue: this.metadata,
        fieldName: 'metadata',
      ),
      addWatermark: addWatermark ?? this.addWatermark,
      watermarkText: _nullableCopyWithValue<String>(
        candidate: watermarkText,
        currentValue: this.watermarkText,
        fieldName: 'watermarkText',
      ),
    );
  }

  @override
  List<Object?> get props => [
        format,
        resolution,
        customWidth,
        customHeight,
        transparentBackground,
        quality,
        embedMetadata,
        metadata,
        addWatermark,
        watermarkText,
      ];
}

/// Predefined export presets for common use cases
class ExportPresets {
  static const socialShare = ExportOptions(
    format: ExportFormat.jpg,
    resolution: ExportResolution.instagram,
    quality: 90,
    embedMetadata: true,
  );

  static const highQualityPng = ExportOptions(
    format: ExportFormat.png,
    resolution: ExportResolution.uhd4k,
    embedMetadata: true,
  );

  static const webOptimized = ExportOptions(
    format: ExportFormat.webp,
    resolution: ExportResolution.fullHd,
    quality: 85,
    embedMetadata: true,
  );

  static const transparentOverlay = ExportOptions(
    format: ExportFormat.png,
    resolution: ExportResolution.fullHd,
    transparentBackground: true,
    embedMetadata: true,
  );
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/export_options.dart';

void main() {
  group('ExportFormat', () {
    test('extension returns correct file extensions', () {
      expect(ExportFormat.png.extension, 'png');
      expect(ExportFormat.jpg.extension, 'jpg');
      expect(ExportFormat.webp.extension, 'webp');
    });

    test('mimeType returns correct MIME types', () {
      expect(ExportFormat.png.mimeType, 'image/png');
      expect(ExportFormat.jpg.mimeType, 'image/jpeg');
      expect(ExportFormat.webp.mimeType, 'image/webp');
    });
  });

  group('ExportResolution', () {
    test('dimensions returns correct values for preset resolutions', () {
      expect(ExportResolution.hd.dimensions, (1280, 720));
      expect(ExportResolution.fullHd.dimensions, (1920, 1080));
      expect(ExportResolution.quadHd.dimensions, (2560, 1440));
      expect(ExportResolution.uhd4k.dimensions, (3840, 2160));
      expect(ExportResolution.instagram.dimensions, (1080, 1080));
      expect(ExportResolution.instagramStory.dimensions, (1080, 1920));
      expect(ExportResolution.twitter.dimensions, (1200, 675));
    });

    test('screen and custom resolutions return null dimensions', () {
      expect(ExportResolution.screen.dimensions, isNull);
      expect(ExportResolution.custom.dimensions, isNull);
    });

    test('isSocialPreset identifies social presets correctly', () {
      expect(ExportResolution.instagram.isSocialPreset, isTrue);
      expect(ExportResolution.instagramStory.isSocialPreset, isTrue);
      expect(ExportResolution.twitter.isSocialPreset, isTrue);
      expect(ExportResolution.fullHd.isSocialPreset, isFalse);
      expect(ExportResolution.uhd4k.isSocialPreset, isFalse);
    });
  });

  group('ExportOptions', () {
    test('default options have sensible values', () {
      const options = ExportOptions();
      expect(options.format, ExportFormat.png);
      expect(options.resolution, ExportResolution.fullHd);
      expect(options.quality, 95);
      expect(options.embedMetadata, isTrue);
      expect(options.transparentBackground, isFalse);
    });

    test('calculatePixelRatio returns correct ratio for preset resolutions',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      // Portrait screen 400x800 -> Full HD adapts to 1080x1920.
      // Ratios: 1080/400 = 2.7, 1920/800 = 2.4 -> max = 2.7
      final ratio = options.calculatePixelRatio(400, 800);
      expect(ratio, closeTo(2.7, 0.1));
    });

    test('calculatePixelRatio is clamped to 8.0 max', () {
      const options = ExportOptions(resolution: ExportResolution.uhd4k);
      // Screen 100x100 -> would need 38.4 ratio, but clamped to 8
      final ratio = options.calculatePixelRatio(100, 100);
      expect(ratio, 8.0);
    });

    test('calculatePixelRatio sanitizes invalid screen dimensions for presets',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);

      expect(options.calculatePixelRatio(-400, -800), 8.0);
    });

    test('getTargetDimensions returns correct dimensions', () {
      const options = ExportOptions(resolution: ExportResolution.instagram);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1080));
    });

    test('getTargetDimensions adapts preset orientation to screen orientation',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1920));
    });

    test('social preset dimensions preserve platform crop contracts', () {
      const instagramStory = ExportOptions(
        resolution: ExportResolution.instagramStory,
      );
      const twitter = ExportOptions(resolution: ExportResolution.twitter);

      expect(instagramStory.getTargetDimensions(1200, 800), (1080, 1920));
      expect(twitter.getTargetDimensions(400, 800), (1200, 675));
      expect(
        instagramStory.calculatePixelRatio(1200, 800),
        closeTo(2.4, 0.01),
      );
    });

    test('custom resolution uses customWidth and customHeight', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (2000, 1500));
    });

    test('custom resolution ignores non-positive dimensions', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 0,
        customHeight: -10,
      );

      expect(options.getTargetDimensions(400, 800), (400, 800));
      expect(options.calculatePixelRatio(400, 800), 1.0);
    });

    test('custom resolution can fall back one axis at a time', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 0,
      );

      expect(options.getTargetDimensions(400, 800), (2000, 800));
      expect(options.calculatePixelRatio(400, 800), 5.0);
    });

    test('screen dimensions used for fallback are at least one pixel', () {
      const options = ExportOptions(resolution: ExportResolution.custom);

      expect(options.getTargetDimensions(0, -20), (1, 1));
      expect(options.calculatePixelRatio(0, -20), 1.0);
    });

    test('copyWith creates new instance with updated values', () {
      const original = ExportOptions();
      final updated = original.copyWith(
        format: ExportFormat.jpg,
        quality: 80,
      );

      expect(updated.format, ExportFormat.jpg);
      expect(updated.quality, 80);
      expect(updated.resolution, original.resolution); // Unchanged
    });

    test('copyWith clears nullable custom dimensions when null is explicit', () {
      const original = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );

      final updated = original.copyWith(
        customWidth: null,
        customHeight: null,
      );

      expect(updated.customWidth, isNull);
      expect(updated.customHeight, isNull);
      expect(updated.getTargetDimensions(400, 800), (400, 800));
    });

    test('copyWith clears nullable provenance fields when null is explicit',
        () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(
        metadata: null,
        watermarkText: null,
      );

      expect(updated.metadata, isNull);
      expect(updated.watermarkText, isNull);
    });

    test('copyWith omits nullable provenance fields without clearing them', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(quality: 80);

      expect(updated.metadata, same(metadata));
      expect(updated.watermarkText, 'Flutter Fractals');
    });
  });

  group('ExportMetadata', () {
    test('toExifMap returns expected keys', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );

      final exif = metadata.toExifMap();
      expect(exif, containsPair('Software', contains('Flutter Fractals')));
      expect(exif, containsPair('Artist', 'Flutter Fractals'));
      expect(exif, containsPair('UserComment', contains('mandelbrot')));
    });
  });

  group('ExportPresets', () {
    test('socialShare preset has correct settings', () {
      expect(ExportPresets.socialShare.format, ExportFormat.jpg);
      expect(ExportPresets.socialShare.resolution, ExportResolution.instagram);
      expect(ExportPresets.socialShare.quality, 90);
    });

    test('highQualityPng preset has correct settings', () {
      expect(ExportPresets.highQualityPng.format, ExportFormat.png);
      expect(ExportPresets.highQualityPng.resolution, ExportResolution.uhd4k);
    });

    test('webOptimized preset has correct settings', () {
      expect(ExportPresets.webOptimized.format, ExportFormat.webp);
      expect(ExportPresets.webOptimized.resolution, ExportResolution.fullHd);
      expect(ExportPresets.webOptimized.quality, 85);
    });

    test('transparentOverlay preset has correct settings', () {
      expect(ExportPresets.transparentOverlay.format, ExportFormat.png);
      expect(ExportPresets.transparentOverlay.transparentBackground, isTrue);
    });
  });
}

